import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';
import { DashboardService } from '../../services/dashboard.service';
import { User } from '../../models/user.model';

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.css']
})
export class DashboardComponent implements OnInit {
  currentUser: User | null = null;
  statistics: any = {};
  loading = true;

  constructor(
    private authService: AuthService,
    private dashboardService: DashboardService,
    private router: Router
  ) {}

  ngOnInit() {
    this.currentUser = this.authService.getCurrentUser();
    this.loadStatistics();
  }

  loadStatistics() {
    this.dashboardService.getStatistics().subscribe({
      next: (data) => {
        this.statistics = data;
        this.loading = false;
      },
      error: (error) => {
        console.error('Error loading statistics:', error);
        this.loading = false;
      }
    });
  }

  logout() {
    this.authService.logout();
    this.router.navigate(['/']);
  }

  navigate(route: string) {
    this.router.navigate([route]);
  }
}
<div class="row mb-4">
  <div class="col-12">
    <h2 class="text-center">Welcome, {{ currentUser?.name || 'Student' }}!</h2>
  </div>
</div>

<div class="row mt-5">
  <div class="col-md-6">
    <div class="card glass">
      <div class="card-body">
        <h5 class="card-title fw-bold">Quick Actions</h5>
        <div class="d-grid gap-3">


          <button class="btn btn-flux"
                  *ngIf="currentUser?.role === 'STUDENT'"
                  (click)="navigate('/complaints')"
                  title="Submit Complaint">
            <i class="bi bi-chat-dots me-2"></i> Submit Complaint
          </button>


          <button class="btn btn-flux"
                  *ngIf="currentUser?.role === 'STUDENT'"
                  (click)="navigate('/leave-requests')"
                  title="Request Leave">
            <i class="bi bi-calendar-check me-2"></i> Request Leave
          </button>


          <button class="btn btn-flux"
                  *ngIf="currentUser?.role === 'STUDENT'"
                  (click)="navigate('/maintenance')"
                  title="Report Maintenance Issue">
            <i class="bi bi-tools me-2"></i> Report Maintenance Issue
          </button>


          <button class="btn btn-flux"
                  *ngIf="currentUser?.role === 'ADMIN' || currentUser?.role === 'WARDEN'"
                  (click)="navigate('/rooms')"
                  title="Manage Rooms">
            <i class="bi bi-building me-2"></i> Manage Rooms
          </button>


          <button class="btn btn-flux"
                  *ngIf="currentUser?.role === 'ADMIN' || currentUser?.role === 'WARDEN'"
                  (click)="navigate('/students')"
                  title="Manage Students">
            <i class="bi bi-person-badge me-2"></i> Manage Students
          </button>


        </div>
      </div>
    </div>
  </div>


  <div class="col-md-6">
    <div class="card glass">
      <div class="card-body">
        <h5 class="card-title fw-bold">System Overview</h5>
        <ul class="list-group list-group-flush glass-list">
          <li class="list-group-item d-flex justify-content-between align-items-center">
            <div class="d-flex align-items-center">
              <i class="bi bi-person-badge me-2"></i> Total Users
            </div>
            <span class="badge bg-primary rounded-pill">{{ statistics.totalUsers || 0 }}</span>
          </li>
          <li class="list-group-item d-flex justify-content-between align-items-center">
            <div class="d-flex align-items-center">
              <i class="bi bi-chat-dots me-2"></i> Total Complaints
            </div>
            <span class="badge bg-secondary rounded-pill">{{ statistics.totalComplaints || 0 }}</span>
          </li>
          <li class="list-group-item d-flex justify-content-between align-items-center">
            <div class="d-flex align-items-center">
              <i class="bi bi-tools me-2"></i> Maintenance Requests
            </div>
            <span class="badge bg-info rounded-pill">{{ statistics.totalMaintenanceRequests || 0 }}</span>
          </li>
          <li class="list-group-item d-flex justify-content-between align-items-center">
            <div class="d-flex align-items-center">
              <i class="bi bi-bed me-2"></i> Occupied Beds
            </div>
            <span class="badge bg-success rounded-pill">{{ statistics.occupiedBeds || 0 }}</span>
          </li>
        </ul>
      </div>
    </div>
  </div>
</div>
